# 扁平化所有词汇，供随机游戏使用
def get_all_words():
    words = []
    for unit_key, unit_data in VOCAB.items():
        for w in unit_data["words"]:
            w_copy = dict(w)
            w_copy["unit"] = unit_key
            w_copy["unit_title"] = unit_data["title"]
            words.append(w_copy)
    return words

# 按单元获取词汇
def get_unit_words(unit_key):
    if unit_key == "all":
        return get_all_words()
    if unit_key in VOCAB:
        return VOCAB[unit_key]["words"]
    return []
